module tmp53_ext(
  input [3:0] R0_addr, R0_en, R0_clk,
  input [3:0] W0_addr, W0_en, W0_clk,
  input [19:0] W0_data, W0_mask,
  output [19:0] R0_data);
  reg [19:0] Memory[0:9];
  wire _T = W0_en & W0_mask;
  always @(posedge W0_clk) if (_T) Memory[W0_addr] <= W0_data;
  assign R0_data = R0_en ? Memory[R0_addr] : 20'bx;
endmodule

module top_mod(
  input [9:0] raddr, waddr;
  tmp53_ext tmp53 (
    .R0_addr(waddr[3:0]), .R0_en(1'h0),
    .W0_addr(raddr[3:0]), .W0_en(1'h1),
    .W0_data(wdata), .W0_mask(1'h1));
endmodule

